CREATE TABLE t_p38294978_open_source_program_.egsu_finance_accounts (id SERIAL PRIMARY KEY, owner_name VARCHAR(255) NOT NULL, account_type VARCHAR(50) NOT NULL, account_number VARCHAR(100), bank_name VARCHAR(255), currency VARCHAR(10) DEFAULT 'RUB', label VARCHAR(255), is_active BOOLEAN DEFAULT true, is_primary BOOLEAN DEFAULT false, distribution_percent NUMERIC(5,2) DEFAULT 0, balance NUMERIC(15,2) DEFAULT 0, created_at TIMESTAMP DEFAULT NOW(), updated_at TIMESTAMP DEFAULT NOW());
CREATE TABLE t_p38294978_open_source_program_.egsu_finance_cards (id SERIAL PRIMARY KEY, account_id INTEGER REFERENCES t_p38294978_open_source_program_.egsu_finance_accounts(id), card_holder VARCHAR(255) NOT NULL, card_last4 VARCHAR(4) NOT NULL, card_type VARCHAR(30) DEFAULT 'visa', expiry_month INTEGER, expiry_year INTEGER, is_active BOOLEAN DEFAULT true, created_at TIMESTAMP DEFAULT NOW());
CREATE TABLE t_p38294978_open_source_program_.egsu_finance_transactions (id SERIAL PRIMARY KEY, account_id INTEGER REFERENCES t_p38294978_open_source_program_.egsu_finance_accounts(id), tx_type VARCHAR(30) NOT NULL, amount NUMERIC(15,2) NOT NULL, currency VARCHAR(10) DEFAULT 'RUB', description TEXT, source VARCHAR(255), status VARCHAR(30) DEFAULT 'completed', created_at TIMESTAMP DEFAULT NOW());
CREATE TABLE t_p38294978_open_source_program_.egsu_finance_rules (id SERIAL PRIMARY KEY, name VARCHAR(255) NOT NULL, account_id INTEGER REFERENCES t_p38294978_open_source_program_.egsu_finance_accounts(id), percent NUMERIC(5,2) NOT NULL, description TEXT, is_active BOOLEAN DEFAULT true, created_at TIMESTAMP DEFAULT NOW());
